function candidate() {
  const fs = require("fs");
  const path = require("path");

  return new Promise((resolve, reject) => {
    fs.readFile(path.join(__dirname, "bundle.wasm"), (error, data) => {
      if (error) {
        reject(error);
        return;
      }

      resolve(data.buffer);
    });
  });
}
